      method: 'POST',
      url: 'https://apply07.grants.gov/grantsws/rest/opportunity/details',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'oppId=' + oppId,
      timeout: 10000,
    });
    return detail;
  } catch (e) {
    return null;
  }
}

